--
-- Table structure for table `factor_effectiveness`
--

DROP TABLE IF EXISTS `factor_effectiveness`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `factor_effectiveness` (
  `factor_id` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '因子ID',
  `evaluation_date` date NOT NULL COMMENT '评估日期',
  `forward_period` int NOT NULL COMMENT '前瞻收益周期(天)',
  `ic_mean` decimal(10,6) DEFAULT NULL COMMENT 'IC均值',
  `ic_std` decimal(10,6) DEFAULT NULL COMMENT 'IC标准差',
  `ic_ir` decimal(10,6) DEFAULT NULL COMMENT 'IC信息比率(IC均值/IC标准差)',
  `ic_win_rate` decimal(5,2) DEFAULT NULL COMMENT 'IC胜率(正值占比%)',
  `latest_ic` decimal(10,6) DEFAULT NULL COMMENT '最新一期IC值',
  `sample_count` int DEFAULT NULL COMMENT '有效样本数',
  `factor_direction` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '因子方向(positive/negative)',
  `extra_info` json DEFAULT NULL COMMENT '额外信息(IC序列等)',
  `created_at` datetime DEFAULT NULL COMMENT '创建时间',
  `updated_at` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`factor_id`,`evaluation_date`,`forward_period`),
  KEY `idx_eff_date_period` (`evaluation_date`,`forward_period`),
  KEY `idx_eff_factor_date` (`factor_id`,`evaluation_date`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

